//-------------------------------------------------------------------------
// 행추가 버튼 클릭 될때 호출 되는 Function
//-------------------------------------------------------------------------
scwin.f_AddRow = async function (e) {
    try{
        let ret = "";

        // 계정코드의 어음 종류에 따라서 validation하는 값이 달라진다.
        if ( acb_billRecvAcctCd.getValue() == ACConstants.BILLRECV_ELEC_BILLRECV) {
            //ret = await $c.gus.cfValidate([ed_billRecvNo,acb_billRecvAcctCd,acb_billRecvStsCd,ed_dueDt,ed_prtDt,ed_prtAmt,ed_clntNo,ed_trustBankbookNo,ed_recDt,ed_chgRsn,ed_acctDeptCd,gr_billReceivable]);
            //20일때는 어음번호 필수가 아님
            console.log("전자채권");
            ret = await $c.gus.cfValidate([acb_billRecvAcctCd,acb_billRecvStsCd,ed_dueDt,ed_prtDt,ed_prtAmt,ed_clntNo,ed_trustBankbookNo,ed_recDt,ed_acctDeptCd]);
            if (!ret){
                return false;
            }

            //정보값의 ByteLength (ASIS validExp 를 TOBE에서 처리가 불가하여 임의 추가함)
            if (ed_billRecvNo.getValue() !="" ){
                if ($c.gus.cfGetByteLength(ed_billRecvNo) > 20) {
                    await $c.win.alert("어음번호은(는) 20자 이하로 입력하십시오.(한글은 10자 이하)");
                    ed_billRecvNo.focus();
                    return false;
                }
            }

            if (ed_chgRsn.getValue() !="" ){
                if ($c.gus.cfGetByteLength(ed_chgRsn) > 100) {
                    await $c.win.alert("적요은(는) 100자 이하로 입력하십시오.(한글은 50자 이하)");
                    ed_chgRsn.focus();
                    return false;
                }
            }
        }else{
            //ret = await $c.gus.cfValidate([ed_billRecvNo,acb_billRecvAcctCd,acb_billRecvStsCd,ed_dueDt,ed_prtDt,ed_prtAmt,ed_clntNo,ed_trustBankbookNo,ed_prtBankNm,ed_recDt,ed_chgRsn,ed_acctDeptCd]);
            ret = await $c.gus.cfValidate([ed_billRecvNo,acb_billRecvAcctCd,acb_billRecvStsCd,ed_dueDt,ed_prtDt,ed_prtAmt,ed_clntNo,ed_trustBankbookNo, ed_recDt,ed_acctDeptCd]);
            if (!ret){
                return false;
            }

            if (ed_billRecvNo.getValue().trim() == "") {
                await $c.win.alert("해당 계정코드의 어음번호는 필수 입력입니다.");
                ed_billRecvNo.focus();
                return false;
            }

            //정보값의 ByteLength (ASIS validExp 를 TOBE에서 처리가 불가하여 임의 추가함)
            if (ed_billRecvNo.getValue() !="" ){
                if ($c.gus.cfGetByteLength(ed_billRecvNo) > 20) {
                    await $c.win.alert("어음번호은(는) 20자 이하로 입력하십시오.(한글은 10자 이하)");
                    ed_billRecvNo.focus();
                    return false;
                }
            }

            if (ed_prtBankNm.getValue().trim() == "") {
                await $c.win.alert("해당 계정코드의 발행은행명은 필수 입력입니다.");
                ed_prtBankNm.focus();
                return false;
            }

            //정보값의 ByteLength (ASIS validExp 를 TOBE에서 처리가 불가하여 임의 추가함)
            if (ed_prtBankNm.getValue() !="" ){
                if ($c.gus.cfGetByteLength(ed_prtBankNm) > 30) {
                    await $c.win.alert("발행은행명은(는) 30자 이하로 입력하십시오.(한글은 15자 이하)");
                    ed_prtBankNm.focus();
                    return false;
                }
            }

            if (ed_chgRsn.getValue() !="" ){
                if ($c.gus.cfGetByteLength(ed_chgRsn) > 100) {
                    await $c.win.alert("적요은(는) 100자 이하로 입력하십시오.(한글은 50자 이하)");
                    ed_chgRsn.focus();
                    return false;
                }
            }
        }
        //UDC코드 히든값 초기화
        ed_clntNo.hidVal = "";
        ed_trustBankbookNo.hidVal = "";
        ed_acctDeptCd.hidVal = "";
        ed_mgntEmpNm.hidVal = "";

        // 기본 초기화관련 내용 함수 호출
        scwin.f_Initial();
    } catch (e) {
       console.log(e);
    }
};

