//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (e) {
    try{
        let ret = "";
        //ret = await $c.gus.cfValidate([ed_billRecvNo,acb_billRecvAcctCd,acb_billRecvStsCd,ed_dueDt,ed_prtDt,ed_clntNo,ed_prtAmt,ed_prtBankNm,ed_trustBankbookNo,ed_acctDeptCd]);

        if (ds_billReceivable.getCellData(ds_billReceivable.getRowPosition(), "billRecvAcctCd") == ACConstants.BILLRECV_ELEC_BILLRECV ) {
            ret = await $c.gus.cfValidate([acb_billRecvAcctCd,acb_billRecvStsCd,ed_dueDt,ed_prtDt,ed_prtAmt,ed_clntNo,ed_trustBankbookNo,ed_recDt,ed_acctDeptCd]);
        }else{
            ret = await $c.gus.cfValidate([ed_billRecvNo,acb_billRecvAcctCd,acb_billRecvStsCd,ed_dueDt,ed_prtDt,ed_prtAmt,ed_clntNo,ed_trustBankbookNo,ed_recDt,ed_acctDeptCd]);
        }
        if (!ret){
            return false;
        }

        //정보값의 ByteLength (ASIS validExp 를 TOBE에서 처리가 불가하여 임의 추가함)
        if (ed_billRecvNo.getValue() !="" ){
            if ($c.gus.cfGetByteLength(ed_billRecvNo) > 20) {
                await $c.win.alert("어음번호은(는) 20자 이하로 입력하십시오.(한글은 10자 이하)");
                ed_billRecvNo.focus();
                return false;
            }
        }

        if (ed_prtBankNm.getValue() !="" ){
            if ($c.gus.cfGetByteLength(ed_prtBankNm) > 40) {
                await $c.win.alert("발행은행명은(는) 30자 이하로 입력하십시오.(한글은 15자 이하)");
                ed_prtBankNm.focus();
                return false;
            }
        }

        if (ed_chgRsn.getValue() !="" ){
            if ($c.gus.cfGetByteLength(ed_chgRsn) > 100) {
                await $c.win.alert("적요은(는) 100자 이하로 입력하십시오.(한글은 50자 이하)");
                ed_chgRsn.focus();
                return false;
            }
        }


        let rowCnt = 0;
        for (let i=0; i<ds_billReceivable.getRowCount(); i++) {
            rowCnt = i + 1;
            // 전자어음을 제외한 나머지 계정코드는 발행은행명이 필수 입력 사항임.
            if ( ds_billReceivable.getCellData(i,"billRecvAcctCd") != ACConstants.BILLRECV_ELEC_BILLRECV ) {
                if (ds_billReceivable.getCellData(i,"billRecvNo").trim() == "") {
                    await $c.win.alert("해당 계정코드의 어음번호는 필수 입력입니다.\n"+rowCnt+"번째 행의 어음번호를 입력 하시기 바랍니다.");
                    ds_billReceivable.setRowPosition(i);//ds_billReceivable.RowPosition = i;
                    $c.gus.cfGoPrevPosition(gr_billReceivable, i); 
                    return false;
                }
                if (ds_billReceivable.getCellData(i,"prtBankNm").trim() == "") {
                    await $c.win.alert("해당 계정코드의 발행은행명은 필수 입력입니다.\n"+rowCnt+"번째 행의 발행은행명을 입력 하시기 바랍니다.");
                    ds_billReceivable.setRowPosition(i);//ds_billReceivable.RowPosition = i;
                    $c.gus.cfGoPrevPosition(gr_billReceivable, i); 
                    return false;
                }
            }

            if ( ds_billReceivable.getCellData(i,"obankCheckYn") == 1 && ds_billReceivable.getCellData(i,"chgRsn").trim() == "" ) {
                await $c.win.alert(rowCnt+"번째 행의 타수여부 체크시는 변경사유를 입력 하셔야 합니다.");
                ds_billReceivable.setRowPosition(i);
                $c.gus.cfGoPrevPosition(gr_billReceivable, i); 
                return false;
            }

            // 수취일은 만기일보다 항상 이전 날짜이어야 한다.
            if (!$c.gus.cfIsAfterDate(ds_billReceivable.getCellData(i,"recDt"), ds_billReceivable.getCellData(i,"dueDt"))) {
                await $c.win.alert(rowCnt+"번째 행의 만기일자는 수취일자 보다 항상 이후 날짜이어야 합니다.");
                ds_billReceivable.setRowPosition(i);
                $c.gus.cfGoPrevPosition(gr_billReceivable, i); 
                return false;
            }

            // 발행일자는 만기일보다 항상 이전 날짜이어야 한다.
            if (!$c.gus.cfIsAfterDate(ds_billReceivable.getCellData(i,"prtDt"), ds_billReceivable.getCellData(i,"dueDt"))) {
                await $c.win.alert(rowCnt+"번째 행의 발행일자는 만기일보다 항상 이전 날짜이어야 합니다.");
                ds_billReceivable.setRowPosition(i);
                $c.gus.cfGoPrevPosition(gr_billReceivable, i); 
                return false;
            }

            // 수취일은 발행일자보다 항상 이후이어햐 한다.
            if (!$c.gus.cfIsAfterDate(ds_billReceivable.getCellData(i,"prtDt"), ds_billReceivable.getCellData(i,"recDt"))) {
                await $c.win.alert(rowCnt+"번째 행의 발행일자는 수취일자보다 항상 이전 날짜이어야 합니다.");
                ds_billReceivable.setRowPosition(i);
                $c.gus.cfGoPrevPosition(gr_billReceivable, i); 
                return false;
            }
        }
        if(await $c.win.confirm(MSG_CM_CRM_001)) {
            $c.sbm.execute(sbm_saveBillReceivable);
        }

    } catch (e) {
       console.log(e);
    }
};

